// Time:  O(n)
// Space: O(1)

class Solution {
public:
    bool canBeValid(string s, string locked) {
        auto check = [&s, &locked](char c) {
            const int begin = (c == '(') ? 0 : size(s) - 1;
            const int end = (c == '(') ? size(s) : -1;
            const int d = (c == '(') ? 1 : -1;
            for (int i = begin, cnt = 0, bal = 0; i != end; i += d) {
                if (locked[i] == '0') {
                    ++cnt;
                } else {
                    bal += (s[i] == c) ? 1 : -1;
                    if (cnt + bal < 0) {
                        return false;
                    }
                }
            }
            return true;
        };

        return size(s) % 2 == 0 && check('(') && check(')');
    }
};

# Time:  O(n)
# Space: O(1)

class Solution(object):
    def canBeValid(self, s, locked):
        """
        :type s: str
        :type locked: str
        :rtype: bool
        """
        if len(s)%2:
            return False
        for direction, c in ((lambda x:x, '('), (reversed, ')')):
            cnt = bal = 0
            for i in direction(xrange(len(s))):
                if locked[i] == '0':
                    cnt += 1
                else:
                    bal += 1 if s[i] == c else -1
                    if cnt+bal < 0:
                        return False
        return True
